import{_ as i,o as a,c as t,ac as e}from"./chunks/framework.DnBnwVZk.js";const g=JSON.parse('{"title":"git仓库使用指定私钥","description":"","frontmatter":{"date":"2025-02-23T10:52:19.000Z","categories":["知识&技巧"],"tags":["git","ssh"],"publish":true},"headers":[],"relativePath":"views/skill/git/git-ssh-multi-user.md","filePath":"views/skill/git/git-ssh-multi-user.md","lastUpdated":1775803235000}'),n={name:"views/skill/git/git-ssh-multi-user.md"};function h(p,s,l,o,r,k){return a(),t("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1740307939000"},[...s[0]||(s[0]=[e(`<h1 id="git仓库使用指定私钥" tabindex="-1">git仓库使用指定私钥 <a class="header-anchor" href="#git仓库使用指定私钥" aria-label="Permalink to &quot;git仓库使用指定私钥&quot;">​</a></h1><p><a href="https://zhuanlan.zhihu.com/p/684059388" target="_blank" rel="noreferrer">全文引用</a></p><p>当不同的git库需要使用不同的private key的时候，可在运行git命令的时候指定私钥 private key。</p><h2 id="使用ssh配置文件" tabindex="-1">使用SSH配置文件 <a class="header-anchor" href="#使用ssh配置文件" aria-label="Permalink to &quot;使用SSH配置文件&quot;">​</a></h2><p>我们可以通过SSH配置文件来指定在git clone过程中使用特定的私钥。</p><p>具体来说，我们可以在~/.ssh/config文件中为不同的私钥创建两个单独的主机。然后，在git clone期间，根据我们想要使用的密钥，我们可以在SSH连接字符串中指定不同的主机。</p><p>如：</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/config</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Host</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> github-work</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">     HostName</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> github.com</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">     IdentityFile</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/id_rsa_work</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ​</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Host</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> github-personal</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">     HostName</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> github.com</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">     IdentityFile</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/id_rsa_personal</span></span></code></pre></div><p>现在，可以通过id_rsa_work私钥访问的存储库上运行git clone命令，我们可以使用github-work作为其主机来指定SSH连接字符串。</p><p>如：</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git@github-work:corporateA/webapp.git</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git@github-personal:bob/blog.git</span></span></code></pre></div><h2 id="使用core-sshcommand" tabindex="-1">使用core.sshCommand <a class="header-anchor" href="#使用core-sshcommand" aria-label="Permalink to &quot;使用core.sshCommand&quot;">​</a></h2><p>Git仓库提供了一个可配置的选项core.sshCommand。当运行任何需要SSH隧道的命令时，此配置将覆盖默认的SSH命令。</p><p>配置 core.sshCommand</p><p><code>git clone -c &quot;core.sshCommand=ssh -i ~/.ssh/id_rsa_work&quot; &lt;git@github.com&gt;:corporateA/webapp.git</code> 以上例子中，使用-c选项在运行时覆盖core.sshCommand。具体来说，我们使用-i选项将SSH命令更改为指向我们想要使用的私钥。</p><p>在存储库级别上持久化core.sshCommand</p><p>我们可以使用git config命令将配置覆盖持久化到存储库级别，而不是每次重复配置覆盖</p><p><code>git config core.sshCommand &quot;ssh -i ~/.ssh/id_rsa_work&quot;</code></p><p>该命令将core.sshCommand配置持久化到仓库中。这意味着Git将在后续的调用中使用该SSH命令。</p><p>可以使用以下命令验证是否配置成功</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> $</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> core.sshCommand</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.ssh/id_rsa_work</span></span></code></pre></div>`,21)])])}const c=i(n,[["render",h]]);export{g as __pageData,c as default};
